// EXPAND LIST IDS -> one item per configured list id
const cfg = $input.first().json;
let ids = cfg.CLICKUP_LIST_IDS;
if (typeof ids === 'string') { try { ids = JSON.parse(ids); } catch (e) { ids = [ids]; } }
if (!Array.isArray(ids)) ids = [ids];
ids = ids.filter(Boolean).map(id => String(id).trim());
if (ids.length === 0) throw new Error('CLICKUP_LIST_IDS is empty - set at least one list id in Set Config.');
return ids.map(id => ({ json: { list_id: id } }));

// FILTER TARGET-STATUS CANDIDATES
// Input: ALL paged responses from the parents-only fetch (subtasks=false).
const cfg = $('Set Config').first().json;
let statuses = cfg.TARGET_STATUSES;
if (typeof statuses === 'string') { try { statuses = JSON.parse(statuses); } catch (e) { statuses = [statuses]; } }
if (!Array.isArray(statuses)) statuses = [];
const targetStatuses = statuses.map(s => String(s).trim().toLowerCase());

const pages = $input.all();

// pagination truncation guard: never silently drop tickets
if (pages.length) {
  const last = pages[pages.length - 1].json || {};
  const lastTasks = (last && last.tasks) || [];
  if (lastTasks.length >= 100 && last.last_page !== true) {
    throw new Error('Pagination likely truncated: last fetched page returned ' + lastTasks.length +
      ' tasks but last_page was not true. Increase the Fetch node pagination maxRequests / check pagination config.');
  }
}

const allTasks = [];
for (const resp of pages) {
  const tasks = (resp.json && resp.json.tasks) || [];
  for (const t of tasks) allTasks.push(t);
}
console.log('Fetched ' + allTasks.length + ' parent tickets across ' + pages.length + ' page(s).');

const results = [];
for (const task of allTasks) {
  if (task.parent) continue;
  const status = ((task.status && task.status.status) || '').toLowerCase();
  if (targetStatuses.length && !targetStatuses.includes(status)) continue;
  results.push({ json: {
    task_id: task.id,
    task_name: task.name,
    status: (task.status && task.status.status) || 'unknown',
    list_id: (task.list && task.list.id) || ''
  }});
}
console.log('Target-status candidates: ' + results.length);

if (results.length === 0) {
  return [{ json: { task_id: '', task_name: 'No matching tickets found', status: 'empty', list_id: '', no_candidates: true } }];
}
return results;

// DYNAMIC BATCH LIMITER
const cfg = $('Set Config').first().json;
const MAX = Number(cfg.MAX_TICKETS_PER_RUN) || 10;
const AUTO = cfg.AUTO_ADJUST_BATCH === true || cfg.AUTO_ADJUST_BATCH === 'true';
const items = $input.all().filter(i => !i.json.no_candidates);
if (items.length === 0) return [];
const limit = AUTO ? items.length : MAX;
const batch = items.slice(0, limit);
const overflow = Math.max(0, items.length - batch.length);
console.log('Batch: processing ' + batch.length + ' of ' + items.length + ' candidate tickets (AUTO=' + AUTO + '). Overflow: ' + overflow);
const sd = $getWorkflowStaticData('global');
sd.currentRun = { scanned: batch.length, updated: 0, tcs_created: 0, failed: 0, parse_failures: 0, started_at: new Date().toISOString() };
return batch.map(item => ({ json: { ...item.json, total_candidates: items.length, overflow_count: overflow } }));

// EVALUATE COVERAGE (per ticket, from the task-detail response)
const detail = $input.first().json;
const cfg = $('Set Config').first().json;
const MIN_DESC = Number(cfg.MIN_DESC_LENGTH) || 100;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const ticket = $('Loop Each Ticket').first().json;

const subtasks = detail.subtasks || [];
const tcChildren = subtasks.filter(st => st.name && st.name.trim().startsWith(TC_PREFIX));
const hasTCs = tcChildren.length > 0;

const requirement = detail.markdown_description || detail.description || detail.text_content || '';
const isThin = requirement.trim().length < MIN_DESC;

let action = 'skip';
if (hasTCs) action = 'skip';
else if (!isThin) action = 'generate';
else action = 'monitor';

return [{ json: {
  task_id: detail.id || ticket.task_id,
  task_name: detail.name || ticket.task_name,
  status: (detail.status && detail.status.status) || ticket.status || 'unknown',
  list_id: (detail.list && detail.list.id) || ticket.list_id || '',
  requirement: requirement,
  has_tcs: hasTCs,
  existing_tc_count: tcChildren.length,
  is_thin: isThin,
  action: action,
  need_generate: action === 'generate'
}}];

// PARSE DEEPSEEK RESPONSE -> one item per test case
const response = $input.first().json;
const cfg = $('Set Config').first().json;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const assignee = cfg.ASSIGNEE_USER_ID || '';

let ticketData = {};
try { ticketData = $('Evaluate Coverage').first().json; }
catch (e) { ticketData = {}; }
try { if (!ticketData.task_id) ticketData = $('Loop Each Ticket').first().json; } catch (e) {}

let textContent = '';
if (response.choices && response.choices[0] && response.choices[0].message) {
  textContent = response.choices[0].message.content || '';
} else if (typeof response === 'string') {
  textContent = response;
}

let clean = textContent.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let testCases = [];
try {
  testCases = JSON.parse(clean);
} catch (e) {
  const m = clean.match(/\[[\s\S]*\]/);
  if (m) {
    try { testCases = JSON.parse(m[0]); }
    catch (e2) {
      return [{ json: { error: true, error_type: 'parse_failure', task_id: ticketData.task_id, task_name: ticketData.task_name, parse_error: e2.message, raw_preview: textContent.substring(0, 300) } }];
    }
  } else {
    return [{ json: { error: true, error_type: 'no_json_found', task_id: ticketData.task_id, task_name: ticketData.task_name, raw_preview: textContent.substring(0, 300) } }];
  }
}

if (!Array.isArray(testCases) || testCases.length === 0) {
  return [{ json: { error: true, error_type: 'empty_array', task_id: ticketData.task_id, task_name: ticketData.task_name } }];
}

return testCases.map((tc, index) => {
  const tc_id = tc.tc_id || ('TC_' + String(index + 1).padStart(3, '0'));
  const title = tc.title || 'Untitled Test Case';
  return { json: {
    tc_id: tc_id,
    title: title,
    tc_name: TC_PREFIX + ' ' + tc_id + ' - ' + title,
    type: tc.type || 'Functional - Positive',
    priority: tc.priority || 'normal',
    module: tc.module || 'General',
    objective: tc.objective || '',
    preconditions: tc.preconditions || 'None',
    steps: tc.steps || '',
    test_data: tc.test_data || 'N/A',
    expected_result: tc.expected_result || '',
    parent_task_id: ticketData.task_id,
    task_name: ticketData.task_name,
    list_id: ticketData.list_id || '',
    assignee_id: assignee,
    tc_index: index + 1,
    total_tcs: testCases.length,
    error: false
  }};
});

// ASSERT COVERAGE (verify each ticket actually got its [TC] subtasks)
const cfg = $('Set Config').first().json;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const MAX_RETRIES = Number(cfg.VERIFY_MAX_RETRIES);
const maxRetries = Number.isFinite(MAX_RETRIES) ? MAX_RETRIES : 2;

const detail = $input.first().json;
const generated = $('Parse TCs from DeepSeek').all().map(i => i.json).filter(t => t && t.error !== true);
if (generated.length === 0) {
  return [{ json: { coverage_ok: true, parent_task_id: (detail && detail.id) || '', note: 'no_generated_tcs' } }];
}

const parentId = generated[0].parent_task_id || (detail && detail.id) || '';
const ticketName = generated[0].task_name || (detail && detail.name) || parentId;

const existingNames = (detail.subtasks || [])
  .map(st => (st.name || '').trim())
  .filter(n => n.startsWith(TC_PREFIX));
const existingSet = new Set(existingNames);

const missing = generated.filter(tc => !existingSet.has((tc.tc_name || '').trim()));

let attempt = 0;
try { attempt = Number($json.verify_attempt) || 0; } catch (e) { attempt = 0; }

if (missing.length === 0) {
  return [{ json: { coverage_ok: true, parent_task_id: parentId, verified: existingNames.length, expected: generated.length } }];
}

if (attempt >= maxRetries) {
  throw new Error('TC coverage incomplete for "' + ticketName + '" (' + parentId + '): found ' +
    (generated.length - missing.length) + '/' + generated.length + ' after ' + attempt +
    ' retr(y/ies). Missing: ' + missing.map(m => m.tc_name).join(' | '));
}

return missing.map(tc => ({ json: { ...tc, coverage_ok: false, verify_attempt: attempt + 1 } }));

const sd = $getWorkflowStaticData('global');
const cfg = $('Set Config').first().json;
const LIMIT = Number(cfg.DASHBOARD_HISTORY_LIMIT) || 30;
const cur = sd.currentRun || { scanned:0, updated:0, tcs_created:0, failed:0, parse_failures:0 };
const scanned = cur.scanned || 0;
const skipped = Math.max(0, scanned - (cur.updated||0) - (cur.failed||0));
const rec = { run_at: new Date().toISOString(), execution_id: $execution.id, tickets_scanned: scanned, tickets_updated: cur.updated||0, tickets_skipped: skipped, tickets_failed: cur.failed||0, tcs_created: cur.tcs_created||0, parse_failures: cur.parse_failures||0, status: (cur.failed||0) > 0 ? 'partial' : 'success' };
if (!Array.isArray(sd.runHistory)) sd.runHistory = [];
sd.runHistory.push(rec);
if (sd.runHistory.length > LIMIT) sd.runHistory = sd.runHistory.slice(-LIMIT);
sd.currentRun = null;
const title = 'QA TC Scanner — run complete';
const text = 'Scanned ' + rec.tickets_scanned + ' | Updated ' + rec.tickets_updated + ' | Skipped ' + rec.tickets_skipped + ' | Failed ' + rec.tickets_failed + ' | TCs created ' + rec.tcs_created;
const card = JSON.stringify({ '@type':'MessageCard', '@context':'http://schema.org/extensions', themeColor:'2EB67D', summary:title, title:'✅ '+title, text:text });
return [{ json: { notify_source:'run_summary', notify_title:title, notify_text:text, teams_webhook_url: cfg.TEAMS_WEBHOOK_URL||'', teams_card: card, alerts_task_id: cfg.ALERTS_TASK_ID||'', clickup_comment_text: '🤖 '+title+'\n\n'+text } }];

const assert = $input.first().json;
const ticketId = assert.parent_task_id || '';
const tcs = $('Parse TCs from DeepSeek').all().map(i => i.json).filter(t => t && t.error !== true);
const ticketName = (tcs[0] && tcs[0].task_name) || ticketId;
const byType = {}; const byPrio = {};
for (const t of tcs) { byType[t.type]=(byType[t.type]||0)+1; byPrio[t.priority]=(byPrio[t.priority]||0)+1; }
const typeLines = Object.keys(byType).map(k => '- ' + k + ': ' + byType[k]).join('\n');
const prioLines = Object.keys(byPrio).map(k => k + '=' + byPrio[k]).join(', ');
const names = tcs.map(t => '- ' + t.tc_name).join('\n');
const comment = '🤖 QA Bot: added ' + tcs.length + ' test case(s).\n\n**By type:**\n' + typeLines + '\n\n**By priority:** ' + prioLines + '\n\n**Test cases:**\n' + names;
const sd = $getWorkflowStaticData('global');
if (!sd.currentRun) sd.currentRun = { scanned:0, updated:0, tcs_created:0, failed:0, parse_failures:0 };
sd.currentRun.updated += 1; sd.currentRun.tcs_created += tcs.length;
return [{ json: { ticket_id: ticketId, ticket_name: ticketName, tc_count: tcs.length, clickup_comment: comment } }];

const e = $input.first().json;
const sd = $getWorkflowStaticData('global');
if (!sd.currentRun) sd.currentRun = { scanned:0, updated:0, tcs_created:0, failed:0, parse_failures:0 };
sd.currentRun.failed += 1; sd.currentRun.parse_failures += 1;
const comment = '🤖 QA Bot: ⚠️ test-case generation FAILED (' + (e.error_type||'unknown') + '). No [TC] subtasks created this run.\n\nRaw model preview:\n```\n' + String(e.raw_preview||'(none)').substring(0,400) + '\n```';
return [{ json: { ticket_id: e.task_id || '', ticket_name: e.task_name || '', error_type: e.error_type||'unknown', clickup_comment: comment } }];

const item = $input.first().json;
const err = (item.execution && item.execution.error) || {};
const msg = (err.message || JSON.stringify(err) || '').toString();
const lastNode = (item.execution && item.execution.lastNodeExecuted) || '';
const lower = msg.toLowerCase();
const sd = $getWorkflowStaticData('global');
const cur = sd.currentRun || { scanned:0, updated:0, tcs_created:0, failed:0, parse_failures:0 };
const LIMIT = Number(item.DASHBOARD_HISTORY_LIMIT) || 30;
if (!Array.isArray(sd.runHistory)) sd.runHistory = [];
sd.runHistory.push({ run_at:new Date().toISOString(), execution_id:(item.execution&&item.execution.id)||'', tickets_scanned:cur.scanned||0, tickets_updated:cur.updated||0, tickets_skipped:Math.max(0,(cur.scanned||0)-(cur.updated||0)-(cur.failed||0)), tickets_failed:cur.failed||0, tcs_created:cur.tcs_created||0, parse_failures:cur.parse_failures||0, status:'error', error:msg.substring(0,300), failed_node:lastNode });
if (sd.runHistory.length > LIMIT) sd.runHistory = sd.runHistory.slice(-LIMIT);
sd.currentRun = null;
let category='unknown', is_auto_fixable=false, action='escalate';
if (lower.includes('429')||lower.includes('rate limit')||lower.includes('too many requests')) { category='transient_rate_limit'; is_auto_fixable=true; action='rerun'; }
else if (lower.includes('econnreset')||lower.includes('etimedout')||lower.includes('timeout')||/\b50\d\b/.test(msg)||lower.includes('socket hang up')) { category='transient_upstream'; is_auto_fixable=true; action='rerun'; }
else if (lastNode==='DeepSeek Generate TCs'||lastNode==='Parse TCs from DeepSeek'||lower.includes('json')||lower.includes('parse')) { category='generation_parse'; is_auto_fixable=true; action='rerun'; }
else if (lower.includes('coverage incomplete')||lastNode==='Assert Coverage') { category='coverage_incomplete'; is_auto_fixable=true; action='rerun'; }
else if (lower.includes('401')||lower.includes('403')||lower.includes('authorization')||lower.includes('unauthorized')||lower.includes('forbidden')) { category='auth'; is_auto_fixable=false; action='escalate'; }
return [{ json: { ...item, error_message:msg, failed_node:lastNode, execution_id:(item.execution&&item.execution.id)||'', execution_url:(item.execution&&item.execution.url)||'', workflow_name:(item.workflow&&item.workflow.name)||'', category, is_auto_fixable, action, known: category!=='unknown' } }];

const base = $('Classify Failure').first().json;
const resp = $input.first().json;
let txt='';
if (resp && resp.choices && resp.choices[0] && resp.choices[0].message) txt = resp.choices[0].message.content || '';
let parsed=null;
try { parsed = JSON.parse(String(txt).replace(/```json/gi,'').replace(/```/g,'').trim()); }
catch(e){ const m=String(txt).match(/\{[\s\S]*\}/); if(m){ try{ parsed=JSON.parse(m[0]); }catch(e2){} } }
const out = { ...base };
if (parsed && typeof parsed==='object') { out.category = parsed.category || base.category; out.is_auto_fixable = parsed.is_auto_fixable === true; out.action = out.is_auto_fixable ? 'rerun' : 'escalate'; out.llm_summary = parsed.human_summary || parsed.suggested_action || ''; }
out.known = true;
return [{ json: out }];

const item = $input.first().json;
const sd = $getWorkflowStaticData('global');
const day = new Date().toISOString().slice(0,10);
if (!sd.reruns) sd.reruns = {};
const used = sd.reruns[day] || 0;
const MAX = Number(item.MAX_AUTO_RERUNS_PER_DAY); const max = Number.isFinite(MAX) ? MAX : 2;
let do_rerun = false;
if (item.is_auto_fixable && used < max) { do_rerun = true; sd.reruns[day] = used + 1; }
return [{ json: { ...item, do_rerun, reruns_used: sd.reruns[day]||used, reruns_max: max } }];

const it = $input.first().json;
const fixed = it.do_rerun ? ('auto re-ran the scanner (' + it.reruns_used + '/' + it.reruns_max + ' today)') : 'no auto-fix applied';
const title = it.is_auto_fixable ? '⚠️ QA Scanner failure (auto-handled)' : '🚨 QA Scanner failure (needs attention)';
const text = 'Workflow: ' + (it.workflow_name||'') + '
Failed node: ' + (it.failed_node||'?') + '
Category: ' + it.category + '
Action: ' + fixed + (it.llm_summary ? '
LLM: ' + it.llm_summary : '') + '
Error: ' + String(it.error_message||'').substring(0,400) + (it.execution_url ? '
Execution: ' + it.execution_url : '');
const color = it.is_auto_fixable ? 'E2A100' : 'D7263D';
const card = JSON.stringify({ '@type':'MessageCard', '@context':'http://schema.org/extensions', themeColor: color, summary: title, title: title, text: text.split('
').join('

') });
return [{ json: { notify_source:'remediation', notify_title:title, notify_text:text, teams_webhook_url: it.TEAMS_WEBHOOK_URL||'', teams_card: card, alerts_task_id: it.ALERTS_TASK_ID||'', clickup_comment_text: '🤖 '+title+'

'+text } }];

const cfg = $('Monitor Config').first().json;
const resp = $input.first().json;
const list = (resp && (resp.data || resp.results)) || (Array.isArray(resp) ? resp : null);
const execs = Array.isArray(list) ? list : [];
const apiDown = !Array.isArray(list);
const now = Date.now();
const STUCK = (Number(cfg.STUCK_MINUTES)||20) * 60000;
const expectedHour = Number(cfg.EXPECTED_RUN_HOUR);
const failed = execs.filter(e => e.status==='error').slice(0,10);
const stuck = execs.filter(e => (e.status==='running' || (!e.stoppedAt && e.finished===false)) && e.startedAt && (now - new Date(e.startedAt).getTime() > STUCK));
const istNow = new Date(now + 5.5*3600000);
const istToday = istNow.toISOString().slice(0,10);
const ranToday = execs.some(e => e.startedAt && new Date(new Date(e.startedAt).getTime()+5.5*3600000).toISOString().slice(0,10) === istToday);
const pastWindow = istNow.getUTCHours() >= ((Number.isFinite(expectedHour)?expectedHour:0) + 1);
const missed = !ranToday && pastWindow;
const signals = [];
if (apiDown) signals.push('Monitor could not read executions from the n8n API.');
if (failed.length) signals.push('Failed executions: ' + failed.length + ' (latest id ' + (failed[0].id||'') + ').');
if (stuck.length) signals.push('Stuck/long-running: ' + stuck.length + ' over ' + (Number(cfg.STUCK_MINUTES)||20) + ' min.');
if (missed) signals.push('HEARTBEAT: scanner has NOT run today (expected ~' + (Number.isFinite(expectedHour)?expectedHour:0) + ':00 IST).');
const report = signals.length > 0;
return [{ json: { report, signals, failed_count:failed.length, stuck_count:stuck.length, missed, api_down:apiDown, TEAMS_WEBHOOK_URL: cfg.TEAMS_WEBHOOK_URL||'', ALERTS_TASK_ID: cfg.ALERTS_TASK_ID||'', DASHBOARD_TASK_ID: cfg.DASHBOARD_TASK_ID||'', DASHBOARD_HISTORY_LIMIT: cfg.DASHBOARD_HISTORY_LIMIT||30 } }];

const it = $input.first().json;
const title = '🩺 QA Scanner health alert';
const text = (it.signals||[]).join('\n');
const color = (it.missed || it.api_down) ? 'D7263D' : 'E2A100';
const card = JSON.stringify({ '@type':'MessageCard', '@context':'http://schema.org/extensions', themeColor: color, summary: title, title: title, text: String(text).split('\n').join('\n\n') });
return [{ json: { notify_source:'monitor', notify_title:title, notify_text:text, teams_webhook_url: it.TEAMS_WEBHOOK_URL||'', teams_card: card, alerts_task_id: it.ALERTS_TASK_ID||'', clickup_comment_text: '🤖 '+title+'\n\n'+text } }];

const it = $input.first().json;
const sd = $getWorkflowStaticData('global');
const hist = Array.isArray(sd.runHistory) ? sd.runHistory : [];
const N = Number(it.DASHBOARD_HISTORY_LIMIT) || 30;
const recent = hist.slice(-N);
let upd=0, fail=0, tcs=0, succ=0;
for (const r of recent){ upd+=r.tickets_updated||0; fail+=r.tickets_failed||0; tcs+=r.tcs_created||0; if(r.status==='success')succ++; }
const rate = recent.length ? Math.round(100*succ/recent.length) : 0;
const last = recent[recent.length-1];
const lastLine = last ? (last.run_at + ' — scanned ' + last.tickets_scanned + ', updated ' + last.tickets_updated + ', skipped ' + last.tickets_skipped + ', failed ' + last.tickets_failed) : 'no runs yet';
const rows = recent.slice(-10).reverse().map(r => '| ' + String(r.run_at).slice(0,16).replace('T',' ') + ' | ' + r.status + ' | ' + (r.tickets_updated||0) + ' | ' + (r.tickets_failed||0) + ' | ' + (r.tcs_created||0) + ' |').join('\n');
const md = '# QA TC Scanner — Dashboard (last ' + recent.length + ' runs)\n\n**Updated:** ' + upd + ' tickets  |  **Failed:** ' + fail + '  |  **TCs created:** ' + tcs + '  |  **Success rate:** ' + rate + '%\n\n**Last run:** ' + lastLine + '\n\n| Run | Status | Updated | Failed | TCs |\n|---|---|---|---|---|\n' + rows + '\n\n_Updated ' + new Date().toISOString() + '_';
return [{ json: { dashboard_md: md, dashboard_task_id: it.DASHBOARD_TASK_ID||'' } }];
